import React, { useState } from 'react';
// import './SlidingLogin.css';   // Comentado temporalmente

function SlidingLogin({ onLogin }) {
  const [isRightPanelActive, setIsRightPanelActive] = useState(false);
  
  // Estados de Registro
  const [regNombre, setRegNombre] = useState('');
  const [regEmail, setRegEmail] = useState('');
  const [regPassword, setRegPassword] = useState('');
  const [regError, setRegError] = useState('');

  // Estados de Login
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  
  const [loading, setLoading] = useState(false);

  const API_URL = 'http://localhost:5000';

  const handleSignUp = async (e) => {
    e.preventDefault();
    setLoading(true);
    setRegError('');

    if (!regNombre || !regEmail || !regPassword) {
      setRegError('Por favor completa todos los campos');
      setLoading(false);
      return;
    }

    try {
      const response = await axios.post(`${API_URL}/registro`, {
        nombre: regNombre,
        email: regEmail,
        password: regPassword
      });

      if (response.status === 201) {
        alert('¡Registro exitoso! Ahora inicia sesión');
        setIsRightPanelActive(false);
        setRegNombre(''); setRegEmail(''); setRegPassword('');
      }
    } catch (error) {
      setRegError(error.response?.data?.error || 'Error al registrar');
    } finally {
      setLoading(false);
    }
  };

  const handleSignIn = async (e) => {
    e.preventDefault();
    setLoading(true);
    setLoginError('');

    if (!loginEmail || !loginPassword) {
      setLoginError('Por favor ingresa email y contraseña');
      setLoading(false);
      return;
    }

    try {
      const response = await axios.post(`${API_URL}/login`, {
        email: loginEmail,
        password: loginPassword
      });

      if (response.status === 200) {
        onLogin(response.data);
      }
    } catch (error) {
      setLoginError(error.response?.data?.error || 'Error al iniciar sesión');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      background: '#05091a',
      padding: '20px'
    }}>
      <div style={{
        background: 'white',
        borderRadius: '16px',
        boxShadow: '0 10px 30px rgba(0,0,0,0.3)',
        width: '100%',
        maxWidth: '800px',
        overflow: 'hidden'
      }}>
        <h1 style={{ textAlign: 'center', padding: '20px', margin: 0, background: '#278BF5', color: 'white' }}>
          ProLife
        </h1>

        <div style={{ display: 'flex', flexDirection: 'row', minHeight: '500px' }}>
          {/* Login */}
          <div style={{ flex: 1, padding: '40px', background: '#fff' }}>
            <h2>Iniciar Sesión</h2>
            <form onSubmit={handleSignIn}>
              <input
                type="email"
                placeholder="Correo electrónico"
                value={loginEmail}
                onChange={e => setLoginEmail(e.target.value)}
                style={{ width: '100%', padding: '12px', margin: '10px 0', borderRadius: '8px', border: '1px solid #ccc' }}
              />
              <input
                type="password"
                placeholder="Contraseña"
                value={loginPassword}
                onChange={e => setLoginPassword(e.target.value)}
                style={{ width: '100%', padding: '12px', margin: '10px 0', borderRadius: '8px', border: '1px solid #ccc' }}
              />
              {loginError && <p style={{ color: 'red' }}>{loginError}</p>}
              <button type="submit" disabled={loading} style={{ width: '100%', padding: '12px', marginTop: '10px' }}>
                {loading ? 'Cargando...' : 'Ingresar'}
              </button>
            </form>
          </div>

          {/* Registro */}
          <div style={{ flex: 1, padding: '40px', background: '#f8f9fa' }}>
            <h2>Crear Cuenta</h2>
            <form onSubmit={handleSignUp}>
              <input
                type="text"
                placeholder="Nombre completo"
                value={regNombre}
                onChange={e => setRegNombre(e.target.value)}
                style={{ width: '100%', padding: '12px', margin: '10px 0', borderRadius: '8px', border: '1px solid #ccc' }}
              />
              <input
                type="email"
                placeholder="Correo electrónico"
                value={regEmail}
                onChange={e => setRegEmail(e.target.value)}
                style={{ width: '100%', padding: '12px', margin: '10px 0', borderRadius: '8px', border: '1px solid #ccc' }}
              />
              <input
                type="password"
                placeholder="Contraseña"
                value={regPassword}
                onChange={e => setRegPassword(e.target.value)}
                style={{ width: '100%', padding: '12px', margin: '10px 0', borderRadius: '8px', border: '1px solid #ccc' }}
              />
              {regError && <p style={{ color: 'red' }}>{regError}</p>}
              <button type="submit" disabled={loading} style={{ width: '100%', padding: '12px', marginTop: '10px' }}>
                {loading ? 'Cargando...' : 'Registrarse'}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default SlidingLogin;
